<span class="line"><span style="color:#F8F8F2;">var profileLink = &#39;&lt;</span><span style="color:#F92672;">a</span><span style="color:#A6E22E;"> href</span><span style="color:#F8F8F2;">=</span><span style="color:#E6DB74;">&quot;&#39; + escapeHtml(userWebsite) + &#39;&quot;</span><span style="color:#F8F8F2;">&gt;Bob&lt;/</span><span style="color:#F92672;">a</span><span style="color:#F8F8F2;">&gt;&#39;;</span></span>
